}

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@attribute [Authorize(Roles = "Admin")]
@inject UserManager<IdentityUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p class="text-muted">Manage all registered users and their role assignments.</p>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Email</th>
                <th>Username</th>
                <th>Roles</th>
                <th>Email Confirmed</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var user in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@user.UserName</td>
                    <td>
                        @if (userRoles.TryGetValue(user.Id, out var roles))
                        {
                            @string.Join(", ", roles)
                        }
                    </td>
                    <td>
                        @if (user.EmailConfirmed)
                        {
                            <span class="badge bg-success">Yes</span>
                        }
                        else
                        {
                            <span class="badge bg-warning">No</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<IdentityUser>? users;
    private Dictionary<string, IList<string>> userRoles = new();

    protected override async Task OnInitializedAsync()
    {
        users = UserManager.Users.ToList();
        foreach (var user in users)
        {
            userRoles[user.Id] = await UserManager.GetRolesAsync(user);
        }
    }
}

